## get strata plot 

  getSummariseTablePlot <- shiny::reactive({
    df <- getSummariseTableData() |>
      # omopgenerics::addSettings() |>
      omopgenerics::splitAll() |>
      dplyr::filter(
        .data$variable_name == "number subjects",
        .data$estimate_name == "count"
      ) |>
      dplyr::mutate(
        n = suppressWarnings(readr::parse_number(as.character(.data$estimate_value)))
      ) |>
      dplyr::filter(!is.na(.data$n))
    
    strata_cols <- intersect(
      input$summarise_table_plot_strata_columns,
      c("region", "imd", "sex", "ethnicity", "prior_dose")
    )
    
    shiny::req(length(strata_cols) > 0)
    
    if (isTRUE(input$summarise_table_plot_combine)) {
      df <- df |>
        dplyr::mutate(
          dplyr::across(dplyr::all_of(strata_cols), ~ dplyr::coalesce(as.character(.x), "NA"))
        ) |>
        tidyr::unite(
          col = "strata_label",
          dplyr::all_of(strata_cols),
          sep = "-",
          remove = FALSE
        ) |>
        dplyr::group_by(.data$strata_label, .data$cohort_name) |>
        dplyr::summarise(n = sum(.data$n, na.rm = TRUE), .groups = "drop")
      
      ggplot2::ggplot(df, ggplot2::aes(x = .data$strata_label, y = .data$n, fill = .data$strata_label)) +
        ggplot2::geom_col(show.legend = FALSE) +
        ggplot2::labs(x = "Strata", y = "n") +
        ggplot2::theme_minimal() +
        ggplot2::facet_wrap(~.data$cohort_name, scales = "free_x") +
        ggplot2::theme(
          axis.text.x = ggplot2::element_text(angle = 45, hjust = 1)
        )
      
    } else {
      df <- df |>
        dplyr::select(dplyr::all_of(strata_cols), .data$n, .data$cohort_name) |>
        tidyr::pivot_longer(
          cols = dplyr::all_of(strata_cols),
          names_to = "strata_name",
          values_to = "strata_level"
        ) |>
        dplyr::filter(!is.na(.data$strata_level)) |>
        dplyr::group_by(.data$strata_name, .data$strata_level, .data$cohort_name) |>
        dplyr::summarise(n = sum(.data$n, na.rm = TRUE), .groups = "drop")
      
      ggplot2::ggplot(df, ggplot2::aes(x = .data$strata_level, y = .data$n, fill = .data$strata_level)) +
        ggplot2::geom_col(show.legend = FALSE) +
        ggplot2::facet_grid(cohort_name~strata_name, scales = "free_x") +
        ggplot2::labs(x = "Strata level", y = "n") +
        ggplot2::theme_minimal() +
        ggplot2::theme(
          axis.text.x = ggplot2::element_text(angle = 45, hjust = 1)
        )
    }
  })
output$summarise_table_plot <- shiny::renderUI({
  x <- getSummariseTablePlot()
  renderInteractivePlot(x, input$summarise_table_plot_interactive)
})

output$summarise_table_plot_download <- shiny::downloadHandler(
  filename = "plot_strata.png",
  content = function(file) {
    ggplot2::ggsave(
