      plot = getSummariseTablePlot(),
      width = as.numeric(input$summarise_table_plot_width),
      height = as.numeric(input$summarise_table_plot_height),
      units = input$summarise_table_plot_units,
      dpi = as.numeric(input$summarise_table_plot_dpi)
    )
  }
)

## get coverage plots

getSummariseCoveragePlot <- function(input_cohort_name) {
  shiny::reactive({
    
    strata_cols_selected <- input[[paste0("summarise_coverage_plot_strata_columns_", input_cohort_name)]]
    print(strata_cols_selected)
    strata_cols_not <- setdiff(
      c("region", "imd", "sex", "ethnicity"),
      strata_cols_selected
    )
    
    strata_cols <- intersect(
      strata_cols_selected,
      c("region", "imd", "sex", "ethnicity")
    )
    
    shiny::req(length(strata_cols) > 0)
    
    df <- getSummariseTableData() |>
      omopgenerics::filterGroup(.data$cohort_name == input_cohort_name) |>
      print()|>
      dplyr::filter(
        .data$variable_name == "vaccinated",
        .data$estimate_name == "percentage"
      ) |>
      dplyr::filter(!is.na(.data$variable_name)) |>
      dplyr::mutate(
        estimate_value = suppressWarnings(
          readr::parse_number(as.character(.data$estimate_value)) / 100
        )
      ) |>
      dplyr::filter(!is.na(.data$estimate_value)) |>
      print() |>
      omopgenerics::filterStrata(.data$prior_dose > 2 & .data$prior_dose != "overall") |>
      omopgenerics::splitStrata() |>
      print()|>
      dplyr::filter(
        dplyr::if_all(dplyr::all_of(strata_cols_not), ~ .x == "overall")
      ) |>
      dplyr::mutate(
        dplyr::across(dplyr::all_of(strata_cols), ~ dplyr::coalesce(as.character(.x), "NA"))
      )
  
    
    if (isTRUE(input[[paste0("summarise_coverage_plot_combine_", input_cohort_name)]])) {
      
      df <- df |>
        tidyr::unite(
          col = "strata_label",
          dplyr::all_of(strata_cols),
          sep = "-",
          remove = FALSE
        ) |>
        dplyr::group_by(.data$strata_label, .data$prior_dose, .data$group_level) |>
        print()|>
        dplyr::summarise(vaccinated = sum(.data$estimate_value, na.rm = TRUE), .groups = "drop") 
      
        print(names(df))
      
      ggplot2::ggplot(df, ggplot2::aes(x = .data$strata_label, y = .data$vaccinated, fill = .data$strata_label)) +
        ggplot2::geom_col(show.legend = FALSE) +
        ggplot2::scale_y_continuous(labels = scales::percent_format()) +
        ggplot2::labs(x = "Strata", y = "Vaccinated") +
        ggplot2::theme_minimal() +
        ggplot2::facet_wrap(~ prior_dose, scales = "free_x") +
        ggplot2::theme(axis.text.x = ggplot2::element_text(angle = 45, hjust = 1))
      
    } else {
      
      df_long <- purrr::map_dfr(strata_cols, \(ii) {
        other_cols <- setdiff(strata_cols, ii)
        
        df |>
          dplyr::filter(
            dplyr::if_all(dplyr::all_of(other_cols), ~ .x == "overall")
          ) |>
          dplyr::transmute(
            prior_dose = .data$prior_dose,
            strata_name = ii,
            strata_level = .data[[ii]],
            vaccinated = .data$estimate_value
          )
      }) |>
        dplyr::group_by(.data$prior_dose, .data$strata_name, .data$strata_level) |>
        dplyr::summarise(vaccinated = mean(.data$vaccinated, na.rm = TRUE), .groups = "drop")
      
      ggplot2::ggplot(
        df_long,
        ggplot2::aes(x = .data$strata_level, y = .data$vaccinated, fill = .data$strata_level)
      ) +
        ggplot2::geom_col(show.legend = FALSE) +
        ggplot2::facet_grid(prior_dose ~ strata_name, scales = "free_x") +
        ggplot2::scale_y_continuous(labels = scales::percent_format()) +
        ggplot2::labs(x = "Strata level", y = "Vaccinated") +
        ggplot2::theme_minimal() +
        ggplot2::theme(axis.text.x = ggplot2::element_text(angle = 45, hjust = 1))
    }
  })
}

